const staticData = $getWorkflowStaticData('global');
const MAX_DEDUP_KEYS = 500;

const getDedupStore = () => {
  if (!staticData.dedupStore || typeof staticData.dedupStore !== 'object') {
    staticData.dedupStore = { order: [], map: {} };
  }
  const dedupStore = staticData.dedupStore;
  if (!Array.isArray(dedupStore.order)) dedupStore.order = [];
  if (!dedupStore.map || typeof dedupStore.map !== 'object') dedupStore.map = {};
  return dedupStore;
};

return items.map((item) => {
  const cid = String(item.json.cid ?? '').trim();
  const sendUserId = String(item.json.send_user_id ?? '').trim();
  const sendMessage = String(item.json.send_message ?? '').trim();
  const dedupKey = `${cid}::${sendUserId}::${sendMessage}`;
  const isDryRun = [true, 'true', 1, '1'].includes(item.json.dry_run);

  if (isDryRun) {
    return {
      json: {
        ...item.json,
        dry_run: true,
        dedup_key: dedupKey,
        is_duplicate: false,
        dedup_skipped: true,
        dedup_skip_reason: 'dry_run',
      },
    };
  }

  const dedupStore = getDedupStore();
  const isDuplicate = Boolean(dedupStore.map[dedupKey]);

  if (!isDuplicate) {
    dedupStore.map[dedupKey] = Date.now();
    dedupStore.order.push(dedupKey);

    while (dedupStore.order.length > MAX_DEDUP_KEYS) {
      const oldest = dedupStore.order.shift();
      if (oldest) delete dedupStore.map[oldest];
    }
  }

  if (isDuplicate) {
    return {
      json: {
        ...item.json,
        dedup_key: dedupKey,
        is_duplicate: true,
        ok: true,
        send: false,
        reason: 'duplicate_message',
        message: 'duplicate message skipped',
        cid,
        send_user_id: sendUserId,
      },
    };
  }

  return {
    json: {
      ...item.json,
      dedup_key: dedupKey,
      is_duplicate: false,
    },
  };
});

return [{
  json: {
    ok: true,
    send: false,
    reason: 'duplicate_message',
    message: 'duplicate message skipped',
    cid: $json.cid ?? '',
    send_user_id: $json.send_user_id ?? '',
  },
}];

const saved = $("保留原始入站消息").item.json;
const original = saved.original ?? saved;
return [{ json: { ...original } }];

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

const getCooldownStore = () => {
  if (!staticData.cooldownStore || typeof staticData.cooldownStore !== 'object') {
    staticData.cooldownStore = {};
  }
  return staticData.cooldownStore;
};

return items.map((item) => {
  const cid = String(item.json.cid ?? '').trim();
  const cooldownRaw = Number(item.json.cooldown_seconds);
  const cooldownSeconds = Number.isFinite(cooldownRaw) && cooldownRaw > 0 ? Math.floor(cooldownRaw) : 15;
  const isDryRun = [true, 'true', 1, '1'].includes(item.json.dry_run);

  if (isDryRun) {
    return {
      json: {
        ...item.json,
        dry_run: true,
        cooldown_active: false,
        cooldown_skipped: true,
        cooldown_skip_reason: 'dry_run',
        cooldown_seconds: cooldownSeconds,
      },
    };
  }

  const cooldownStore = getCooldownStore();
  const lastAllowedAt = Number(cooldownStore[cid] ?? 0);
  const elapsedSeconds = (now - lastAllowedAt) / 1000;

  if (cid && lastAllowedAt > 0 && elapsedSeconds < cooldownSeconds) {
    const remainingSeconds = Math.max(1, Math.ceil(cooldownSeconds - elapsedSeconds));
    return {
      json: {
        ...item.json,
        cooldown_active: true,
        ok: true,
        send: false,
        reason: 'cooldown_active',
        message: 'conversation cooldown active',
        cid,
        cooldown_seconds: cooldownSeconds,
        remaining_seconds: remainingSeconds,
      },
    };
  }

  if (cid) {
    cooldownStore[cid] = now;
  }

  return {
    json: {
      ...item.json,
      cooldown_active: false,
      cooldown_seconds: cooldownSeconds,
    },
  };
});

return [{
  json: {
    ok: true,
    send: false,
    reason: 'cooldown_active',
    message: 'conversation cooldown active',
    cid: $json.cid ?? '',
    cooldown_seconds: Number($json.cooldown_seconds ?? 15),
    remaining_seconds: Number($json.remaining_seconds ?? 0),
  },
}];

return items.map((item) => ({
  json: {
    ...item.json,
    handoff: false,
    handoff_reason: '',
    route_reason: String(item.json.route_reason || 'default_openclaw'),
    should_send: true,
    rule_reply: '',
  },
}));

const sourceItems = $("保留商品上下文请求原始 payload").all();

const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  return '';
};

return items.map((item, index) => {
  const snapshot = item.json || {};
  const sourceWrapper = (sourceItems[index] && sourceItems[index].json) || {};
  const original = sourceWrapper.item_context_original || sourceWrapper || {};

  let item_context = null;
  let item_context_status = 'missing';
  let item_context_reason = 'snapshot_unavailable';

  if (snapshot.ok === true) {
    item_context = {
      available: true,
      source: 'items_snapshot',
      item_count: Number(snapshot.item_count ?? 0),
      items: Array.isArray(snapshot.items) ? snapshot.items : [],
      section_counts: snapshot.section_counts || {},
      metadata: snapshot.metadata || {},
    };
    item_context_status = 'available';
    item_context_reason = '';
  } else if (pickText(snapshot.reason)) {
    item_context_status = 'missing';
    item_context_reason = pickText(snapshot.reason);
  } else if (pickText(snapshot.error?.message) || pickText(snapshot.error)) {
    item_context_status = 'error';
    item_context_reason = pickText(snapshot.error?.message) || pickText(snapshot.error);
  } else if (pickText(snapshot.message)) {
    item_context_status = 'error';
    item_context_reason = pickText(snapshot.message);
  }

  return {
    json: {
      ...original,
      cid: original.cid,
      send_user_id: original.send_user_id,
      send_message: original.send_message,
      content_type: original.content_type,
      dry_run: original.dry_run,
      risk: original.risk,
      risk_reason: original.risk_reason,
      handoff: original.handoff,
      handoff_reason: original.handoff_reason,
      route_reason: original.route_reason,
      should_send: original.should_send,
      cooldown_seconds: original.cooldown_seconds,
      max_reply_chars: original.max_reply_chars,
      item_context,
      item_context_status,
      item_context_reason,
    },
  };
});

const contextItems = $("保留 OpenClaw 请求上下文").all();

const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  return '';
};

const parseBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const lower = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(lower)) return true;
    if (['false', '0', 'no', 'n'].includes(lower)) return false;
  }
  return null;
};

return items.map((item, index) => {
  const response = item.json || {};
  const contextWrapper = (contextItems[index] && contextItems[index].json) || {};
  const context = contextWrapper.openclaw_context || contextWrapper || {};

  const candidates = [
    ['reply', response.reply],
    ['text', response.text],
    ['message', response.message],
    ['content', response.content],
    ['data.reply', response.data?.reply],
    ['data.text', response.data?.text],
    ['data.message', response.data?.message],
    ['data.content', response.data?.content],
    ['choices[0].message.content', response.choices?.[0]?.message?.content],
    ['choices[0].text', response.choices?.[0]?.text],
  ];

  let openclawReply = '';
  let source = 'none';
  for (const [name, value] of candidates) {
    const text = pickText(value);
    if (text) {
      openclawReply = text;
      source = name;
      break;
    }
  }

  const handoffRaw = parseBool(response.handoff);
  const nestedHandoffRaw = parseBool(response.data?.handoff);
  const handoff = handoffRaw ?? nestedHandoffRaw ?? false;

  const shouldSendRaw = parseBool(response.should_send);
  const nestedShouldSendRaw = parseBool(response.data?.should_send);
  let shouldSend = shouldSendRaw ?? nestedShouldSendRaw;
  if (shouldSend === null) shouldSend = true;

  const openclawReason =
    pickText(response.reason) ||
    pickText(response.data?.reason) ||
    pickText(response.handoff_reason) ||
    pickText(response.data?.handoff_reason);

  const openclawError =
    pickText(response.error?.message) ||
    pickText(response.error) ||
    pickText(response.data?.error?.message) ||
    pickText(response.data?.error);

  return {
    json: {
      ...context,
      cid: context.cid,
      send_user_id: context.send_user_id,
      send_message: context.send_message,
      risk: context.risk,
      risk_reason: context.risk_reason,
      route_reason: context.route_reason,
      handoff: handoff,
      handoff_reason: handoff ? (openclawReason || String(context.handoff_reason || 'openclaw_handoff')) : String(context.handoff_reason || ''),
      should_send: shouldSend,
      reply: openclawReply,
      openclaw_reply: openclawReply,
      openclaw_response: response,
      openclaw_reply_source: source,
      openclaw_reason: openclawReason,
      openclaw_error: openclawError,
      item_context_status: context.item_context_status,
      item_context_reason: context.item_context_reason,
      cooldown_seconds: context.cooldown_seconds,
      max_reply_chars: context.max_reply_chars,
    },
  };
});

const maxReplyChars = Number($json.max_reply_chars || 80);
const blocked = /(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i;
let text = String($json.reply || '').replace(/<think>[\s\S]*?<\/think>/gi, ' ');
text = text.replace(/```(?:thinking|reasoning|analysis)[\s\S]*?```/gi, ' ');
const markers = ['最终回复：','最终回复:','买家可见回复：','买家可见回复:','回复：','回复:'];
for (const marker of markers) {
  const idx = text.lastIndexOf(marker);
  if (idx >= 0) text = text.slice(idx + marker.length);
}
text = text.split(/\r?\n/)
  .map((line) => line.replace(/^\s*(?:[-*+]|#{1,6}|>|\d+[.)])\s*/, '').trim())
  .filter((line) => line && !/^(思考|分析|推理|判断|策略|步骤|理由|reasoning|analysis)/i.test(line))
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();
if (blocked.test(text)) text = '平台内沟通就行，合适可拍';
text = text.slice(0, maxReplyChars);
return [{ json: { ...$json, sanitized_reply: text } }];

let final_reply = String($json.sanitized_reply || '').trim();
if (/(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i.test(final_reply)) {
  final_reply = '平台内沟通就行，合适可拍';
}
return [{ json: { ...$json, final_reply } }];

const toTrue = (value) => [true, 'true', 1, '1'].includes(value);
const toFalse = (value) => [false, 'false', 0, '0'].includes(value);

const finalReply = String($json.final_reply || '').trim();
const openclawError = String($json.openclaw_error || '').trim();
const openclawReason = String($json.openclaw_reason || '').trim();

let handoff = toTrue($json.handoff);
let handoffReason = String($json.handoff_reason || '').trim();
let shouldSend = !toFalse($json.should_send);
let routeReason = String($json.route_reason || 'default_openclaw').trim() || 'default_openclaw';

if (openclawError) {
  handoff = true;
  shouldSend = false;
  routeReason = 'system_exception';
  if (!handoffReason) {
    handoffReason = `openclaw_error:${openclawError.slice(0, 160)}`;
  }
} else if (handoff) {
  shouldSend = false;
  routeReason = 'openclaw_handoff';
  if (!handoffReason) {
    handoffReason = openclawReason || 'openclaw_requested_handoff';
  }
} else if (!shouldSend) {
  routeReason = 'openclaw_should_send_false';
  if (!handoffReason) {
    handoffReason = openclawReason || 'openclaw_blocked_send';
  }
} else if (!finalReply) {
  handoff = true;
  shouldSend = false;
  routeReason = 'openclaw_no_valid_reply';
  if (!handoffReason) {
    handoffReason = 'openclaw_no_valid_reply';
  }
}

const reason = shouldSend ? 'ready_to_send' : (routeReason || 'blocked');

return [{
  json: {
    ...$json,
    send: shouldSend,
    should_send: shouldSend,
    handoff,
    handoff_reason: handoffReason,
    route_reason: routeReason,
    reason,
    final_reply: finalReply,
  },
}];
